-- AutoHire migration 027 — demo fleet: 50 cars in the United States.
--
-- Adds the US market (country 'US', priced in USD) alongside Rwanda, Dubai and China,
-- so the country selector and multi-currency pricing have a fourth market. 38 of the
-- 50 are electric, matching the fleet's green story.
--
-- Photo URLs use the same `loremflickr.com/.../<keyword>?lock=<n>` descriptor shape as
-- migrations 024/026. Nothing ever fetches loremflickr: web/src/lib/images.ts reads the
-- keyword + lock and maps them onto a curated, subject-verified Wikimedia photo pool.
-- Keep `<make>` lowercase and matching a pool key in images.ts (tesla, toyota, nissan,
-- hyundai, kia, volkswagen, bmw, mercedes, polestar).
--
-- Requires migration-023 (listings.country + price_currency) and migration-022 (fx_rates,
-- where USD is the base). Safe to re-run: the cars are deleted + reinserted.
--
-- NOTE the `demo-uscar-` id prefix: migration-024 ends with
--   delete from listings where id like 'demo-car-%'
-- so a `demo-car-us-` prefix would be wiped whenever 024 is re-run.
--
-- Remove for good with:  delete from listings where id like 'demo-uscar-%';
--
-- Apply in the Supabase SQL editor.

-- US demo hosts (one fleet business, one individual).
insert into profiles
  (id, full_name, email, phone, role, joined_at, verification, rating_avg, rating_count,
   owner_type, business_name, payout_terms, insurance_type, vehicle_count)
values
  ('demo-host-us-1', 'Bay Area EV Rentals', 'fleet@bayareaev.example', '+14155550142', 'owner', '2025-02-01', 'verified', 4.9, 210, 'business', 'Bay Area EV Rentals', 'net_30', 'commercial', 25),
  ('demo-host-us-2', 'Marcus Bennett', 'marcus.bennett@example.com', '+12125550188', 'owner', '2025-02-01', 'verified', 4.7, 64, 'individual', null, 'per_trip', 'platform_provided', 25)
on conflict (id) do nothing;

-- 50 demo cars across 10 US cities. Delete-then-insert so re-running refreshes them.
delete from listings where id like 'demo-uscar-%';
insert into listings
  (id, title, host_id, owner_type, category, make, model, year, seats, transmission, fuel,
   price_per_day_rwf, price_currency, country, location, city, photos, features, booking_mode,
   rating_avg, rating_count, status, lat, lng)
